using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    // reflection-based resolver — generates metadata on the fly
    TypeInfoResolver = new DefaultJsonTypeInfoResolver(),
    WriteIndented = true
};

// ── 1. Strongly-typed metadata ──────────────────────────────────────────
// GetTypeInfo<T>() returns JsonTypeInfo<T> directly — no cast needed.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Type        : {personInfo.Type.Name}");
Console.WriteLine($"Kind        : {personInfo.Kind}");
Console.WriteLine($"Properties  : {string.Join(", ", personInfo.Properties.Select(p => p.Name))}");

// Round-trip through the typed info to prove it works
string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized  : {json}");

Person? back = JsonSerializer.Deserialize(json, personInfo);
Console.WriteLine($"Deserialized: {back}");

Console.WriteLine();

// ── 2. Probe without throwing ───────────────────────────────────────────
// TryGetTypeInfo returns false instead of throwing when metadata isn't
// resolvable (e.g. the resolver doesn't know about that type, or the
// options are locked to a source-gen context that omits it).

// A type the resolver CAN handle:
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"Person  -> found ({found!.Type.Name})");
else
    Console.WriteLine("Person  -> NOT found");

// Use a restricted resolver that only knows about string:
var restricted = new JsonSerializerOptions
{
    TypeInfoResolver = new RestrictedResolver()
};

if (restricted.TryGetTypeInfo(typeof(Person), out _))
    Console.WriteLine("Person  -> found in restricted resolver");
else
    Console.WriteLine("Person  -> NOT found in restricted resolver (expected)");

if (restricted.TryGetTypeInfo(typeof(string), out JsonTypeInfo? strInfo))
    Console.WriteLine($"string  -> found in restricted resolver ({strInfo!.Type.Name})");
else
    Console.WriteLine("string  -> NOT found in restricted resolver");

// ─── helpers ────────────────────────────────────────────────────────────
record Person(string Name, int Age);

/// <summary>
/// A resolver that only provides metadata for <see cref="string"/>.
/// </summary>
sealed class RestrictedResolver : IJsonTypeInfoResolver
{
    private static readonly DefaultJsonTypeInfoResolver _inner = new();

    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) =>
        type == typeof(string) ? _inner.GetTypeInfo(type, options) : null;
}

